VALUES
('real-estate-moex-00719', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙締結買賣甲所有之 A 屋的契約，乙並先為部分價金之給付。其後，乙未依約定期限給付 剩餘價金。就甲以乙履行遲延而解除A屋買賣契約之情形，下列敘述，何者正確？', '["經甲定期間催告乙履行，甲得於經相當期限後，不須再為催告，即得解除契約", "甲僅限於法律規定之事由始得解除，不得與乙約定合意解除之事由", "契約經解除後，甲、乙互負回復原狀的義務，甲不得向乙請求損害賠償", "契約經解除後，因乙有可歸責事由，甲返還乙已給付之價金時，不須附加利息"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00720', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '就下列甲、乙間之法律關係，何者為非經登記不生效力的情形？', '["甲、乙間締結買賣甲之不動產的契約時", "乙繼承被繼承人甲之不動產時", "甲以其土地供乙設定不動產役權時", "甲將其有抵押權擔保之債權讓與予乙時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00721', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '就甲、乙、丙三人對丁負有平均分擔之300萬元連帶債務的情形，下列敘述，何者正確？', '["甲對丁為債務之承認而中斷時效時，其效力亦及於乙、丙之債務", "丁請求甲支付全額獲勝訴判決後，仍未能自甲受償時，得再請求乙支付全額", "甲清償全額後，如乙不能償還其分擔額，甲亦僅能向丙求償100萬元", "甲對丁清償100萬元後，丁即不得再次向甲請求支付剩餘之200萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00722', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙分別共有 A 地，各有二分之一應有部分。在甲乙未有任何協議之情形下，下列敘述，何 者正確？', '["甲得以其應有部分供丙設定普通地上權", "甲不得將其應有部分出賣、並移轉登記予丁", "甲僅得於其應有部分種植作物", "甲得以其應有部分供戊設定普通抵押權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00723', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者不得為抵押權之標的物？', '["不動產役權", "地上權", "農育權", "典權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00724', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲育有子女乙，丙育有子女丁、戊，乙男與丁女結婚後育有子女己。就此情形，下列敘述何者錯誤？', '["甲、丁為直系姻親", "乙、戊為旁系姻親", "甲、丙為旁系姻親", "己、戊為旁系血親"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00725', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有之A土地上之B建物讓與乙時，在房屋得使用期限內，乙與甲間有何法律關係？', '["推定有租賃關係", "視為有租賃關係", "推定有普通地上權關係", "視為有普通地上權關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00726', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙婚後生育有子女丙、丁、戊。戊與己結婚生育有子女庚、辛後，不幸早於其父母去世。就 甲高齡過世後遺下之財產，下列法定繼承人之應繼分比例，何者正確？', '["乙二分之一、丙四分之一、丁四分之一", "乙三分之一、丙三分之一、丁三分之一", "乙四分之一、丙四分之一、丁四分之一、己四分之一", "乙四分之一、丙四分之一、丁四分之一、庚八分之一、辛八分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00727', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於遺囑之敘述，何者正確？', '["十八歲之限制行為能力人所為之遺囑，當然無效", "受輔助宣告之成年人所為之遺囑，當然無效", "口授遺囑，自遺囑人能依其他方式為遺囑之時起，經過三個月而失其效力", "公證人的受僱人得為公證遺囑之見證人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00728', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依我國民法之規定，下列關於子女姓氏之敘述，何者錯誤？', '["父母於子女出生登記前，應以書面約定子女從父姓或母姓。未約定或約定不成者，於戶政事務 所抽籤決定之", "子女經出生登記後，於未成年前，得由父母以書面約定變更為父姓或母姓", "子女已成年者，得變更為父姓或母姓", "非婚生子女從母姓。經生父認領者，從父姓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00729', 'real-estate', 'real-estate-moex-108-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙為夫妻，育有一子丙，並共同收養丁為養子。某日甲因交通意外去世，未留有遺囑，請問依 我國民法的規定，下列敘述，何者錯誤？', '["乙、丙、丁三人得以繼承", "乙、丙、丁三人之應繼分各為三分之一", "在分割遺產前，乙、丙、丁三人對於遺產全部按其應繼分為分別共有", "繼承人對於甲之債務，以因繼承所得遺產為限，負清償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "28e8aac755ab", "answer_pdf_sha1": "84fca264a81a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
