  ('real-estate-moex-00741', 'real-estate', 'real-estate-moex-107-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '於採土地開發分析法之資本利息綜合利率之計算中，如果資本利息年利率為3%，土地價值比率 為40%，建物價值比率為60%，開發年數為3年，請問資本利息綜合利率為何？', '["9%", "6.3%", "4.5%", "3%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "43a03d156a9c", "answer_pdf_sha1": "52c8012d8e1f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
